public void planRoute(String origin, String destination) {
    GeoApiContext context = new GeoApiContext.Builder()
            .apiKey("YOUR_API_KEY")
            .build();

    DirectionsApiRequest request = DirectionsApiRequest.builder()
            .origin(origin)
            .destination(destination)
            .mode(TravelMode.DRIVING)
            .build();

    Task<DirectionsResult> resultTask = request.await(context);
    resultTask.addOnSuccessListener(directionsResult -> {
        List<Route> routes = directionsResult.routes();
        if (!routes.isEmpty()) {
            Route route = routes.get(0);
            List<Leg> legs = route.legs();
